(1, '{\"en\": \"Needs analysis\", \"fr\": \"Analyse du besoin\"}', '{\"en\": \"We study your drawings, specifications and technical constraints to properly frame your project.\", \"fr\": \"Nous étudions vos plans, cahier des charges et contraintes techniques pour bien cadrer votre projet.\"}', '01', 1, '2026-05-14 09:04:21', '2026-05-20 16:34:37'),
(2, '{\"en\": \"Technical study\", \"fr\": \"Étude technique\"}', '{\"en\": \"Feasibility analysis and identification of suitable processes for your project.\", \"fr\": \"Analyse de faisabilité et identification des procédés adaptés à votre projet.\"}', '02', 2, '2026-05-14 09:04:21', '2026-05-20 16:34:37'),
(3, '{\"en\": \"Supplier selection\", \"fr\": \"Sélection fournisseur\"}', '{\"en\": \"Identification and qualification of partner workshops best suited to your technical requirements.\", \"fr\": \"Identification et qualification des ateliers partenaires les mieux adaptés à vos exigences techniques.\"}', '03', 3, '2026-05-14 09:04:21', '2026-05-20 16:34:37'),
(4, '{\"en\": \"Prototype / pre-production\", \"fr\": \"Prototype / pré-série\"}', '{\"en\": \"Production of validation pieces to confirm conformity before launching production.\", \"fr\": \"Fabrication de pièces de validation pour confirmer la conformité avant le lancement de la production.\"}', '04', 4, '2026-05-14 09:04:21', '2026-05-20 16:34:38'),
(5, '{\"en\": \"Production\", \"fr\": \"Production\"}', '{\"en\": \"Launch of series production with monitoring throughout the process.\", \"fr\": \"Lancement de la fabrication série avec suivi de production tout au long du processus.\"}', '05', 5, '2026-05-14 09:04:21', '2026-05-20 16:34:38'),
(6, '{\"en\": \"Quality control\", \"fr\": \"Contrôle qualité\"}', '{\"en\": \"Inspection, production monitoring and compliance with European standards before shipping.\", \"fr\": \"Inspection, suivi de production et conformité aux normes européennes avant expédition.\"}', '06', 6, '2026-05-14 09:04:21', '2026-05-20 16:34:38'),
(7, '{\"en\": \"Delivery\", \"fr\": \"Livraison\"}', '{\"en\": \"Transport organisation to France and coordination with your receiving department.\", \"fr\": \"Organisation du transport vers la France et coordination avec votre service réception.\"}', '07', 7, '2026-05-14 09:04:21', '2026-05-20 16:34:38');

