INSERT INTO `pages` (`id`, `title`, `content`, `hero_heading`, `hero_lede`, `services_lede`, `why_eyebrow`, `why_heading`, `why_image`, `why_caption`, `why_metric1_value`, `why_metric1_label`, `why_metric2_value`, `why_metric2_label`, `why_item1_title`, `why_item1_desc`, `why_item2_title`, `why_item2_desc`, `why_item3_title`, `why_item3_desc`, `why_item4_title`, `why_item4_desc`, `slug`, `published`, `hero_image`, `created_at`, `updated_at`, `priority`, `meta_title`, `meta_description`) VALUES
(2, '{\"fr\":\"Services\",\"en\":\"Services\"}', '{\"en\":\"\"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'services', 1, 'pages/2HwGJPIe6sFqg2loZbQHvRXPWxXPspGxAJLRIp1v.jpg', '2026-05-13 17:44:58', '2026-05-15 19:32:48', 2, '{\"fr\":\"Nos services de sous-traitance industrielle | Fab Sourcing\",\"en\":\"Our Industrial Subcontracting Services | Fab Sourcing\"}', '{\"fr\":\"Fab Sourcing vous accompagne à chaque étape : sourcing, qualité, logistique. Externalisation en Bulgarie clé en main.\",\"en\":\"Fab Sourcing guides you through every step: sourcing, quality control, logistics. Turnkey outsourcing in Bulgaria.\"}'),
(3, '{\"fr\":\"Pourquoi l\'Europe de l\'Est\",\"en\":\"Why Eastern Europe\"}', '{\"en\":\"\"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'why-eastern-europe', 1, NULL, '2026-05-13 17:44:58', '2026-05-14 18:09:02', 3, '{\"fr\":\"Pourquoi l\'Europe de l\'Est pour votre production ? | Fab Sourcing\",\"en\":\"Why Source from Eastern Europe? | Fab Sourcing\"}', '{\"fr\":\"Bulgarie et Roumanie : qualité européenne certifiée, coûts réduits de 40 à 60 %. Découvrez les avantages de la sous-traitance en Europe de l\'Est.\",\"en\":\"Bulgaria and Romania: certified European quality, 40–60% cost reduction. Discover the benefits of Eastern European industrial subcontracting.\"}'),
(4, '{\"fr\":\"Méthodologie\",\"en\":\"Methodology\"}', '{\"en\":\"\"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'methodology', 1, NULL, '2026-05-13 17:44:58', '2026-05-14 18:09:02', 4, '{\"fr\":\"Notre méthodologie en 7 étapes | Fab Sourcing\",\"en\":\"Our 7-Step Methodology | Fab Sourcing\"}', '{\"fr\":\"De l\'analyse de votre besoin à la livraison : découvrez notre processus en 7 étapes pour une externalisation industrielle sans risque.\",\"en\":\"From needs analysis to delivery: discover our 7-step process for risk-free industrial outsourcing.\"}'),
(5, '{\"fr\":\"À propos\",\"en\":\"About\"}', '{\"en\":\"\"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'about', 1, NULL, '2026-05-13 17:44:58', '2026-05-14 18:09:02', 5, '{\"fr\":\"À propos de Fab Sourcing — Thierry Sudol\",\"en\":\"About Fab Sourcing — Thierry Sudol\"}', '{\"fr\":\"Fab Sourcing, spécialiste de la sous-traitance industrielle en Bulgarie depuis 2010. Fondé par Thierry Sudol, expert terrain en fabrication métallique.\",\"en\":\"Fab Sourcing, specialist in industrial subcontracting in Bulgaria since 2010. Founded by Thierry Sudol, on-the-ground expert in metalwork manufacturing.\"}'),
(6, '{\"fr\":\"Contact\",\"en\":\"Contact\"}', '{\"en\":\"\"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'contact', 1, NULL, '2026-05-13 17:44:58', '2026-05-14 18:09:02', 6, '{\"fr\":\"Contactez Fab Sourcing — Réponse sous 48 h\",\"en\":\"Contact Fab Sourcing — Reply within 48 Hours\"}', '{\"fr\":\"Décrivez votre projet de sous-traitance industrielle. Thierry Sudol vous répond personnellement sous 48 heures.\",\"en\":\"Describe your industrial outsourcing project. Thierry Sudol will reply personally within 48 hours.\"}'),
(7, '{\"fr\":\"Mentions légales\",\"en\":\"Legal Notice\"}', '{\"fr\":\"<h2>Éditeur du site</h2><p>Fab Sourcing — Thierry Sudol<br>1, route Neuve<br>24150 Saint-Capraise-de-Lalinde<br>France</p><p>Email : tsudol.fabtec@yahoo.com<br>Téléphone : +33 (0)7 82 08 51 17</p><h2>Hébergement</h2><p>Ce site est hébergé par un prestataire établi au sein de l\'Union Européenne.</p><h2>Propriété intellectuelle</h2><p>L\'ensemble des contenus présents sur ce site (textes, images, graphiques) sont la propriété exclusive de Fab Sourcing, sauf mention contraire. Toute reproduction, diffusion ou utilisation sans autorisation préalable est interdite.</p><h2>Responsabilité</h2><p>Fab Sourcing s\'efforce de fournir des informations exactes et à jour. Toutefois, la société ne saurait être tenue responsable des erreurs ou omissions, ni de tout préjudice découlant de l\'utilisation des informations publiées.</p>\",\"en\":\"<h2>Site Publisher</h2><p>Fab Sourcing — Thierry Sudol<br>1, route Neuve<br>24150 Saint-Capraise-de-Lalinde<br>France</p><p>Email: tsudol.fabtec@yahoo.com<br>Phone: +33 (0)7 82 08 51 17</p><h2>Hosting</h2><p>This website is hosted by a provider established within the European Union.</p><h2>Intellectual Property</h2><p>All content on this site (text, images, graphics) is the exclusive property of Fab Sourcing unless otherwise stated. Any reproduction, distribution or use without prior authorisation is prohibited.</p><h2>Liability</h2><p>Fab Sourcing endeavours to provide accurate and up-to-date information. However, the company cannot be held liable for errors or omissions, or for any loss arising from the use of published information.</p>\"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'mentions-legales', 1, NULL, '2026-05-13 19:46:27', '2026-05-14 18:09:02', NULL, '{\"fr\":\"Mentions légales | Fab Sourcing\",\"en\":\"Legal Notice | Fab Sourcing\"}', '{\"fr\":\"Mentions légales du site fab-sourcing.fr — Thierry Sudol, éditeur.\",\"en\":\"Legal notice for fab-sourcing.fr — Thierry Sudol, publisher.\"}'),
(8, '{\"fr\":\"Politique de confidentialité\",\"en\":\"Privacy Policy\"}', '{\"fr\":\"<h2>Données collectées</h2><p>Lorsque vous soumettez le formulaire de contact, nous collectons les informations suivantes : nom, entreprise (optionnel), adresse email, numéro de téléphone (optionnel), et votre message. Ces données sont utilisées uniquement pour répondre à votre demande.</p><h2>Conservation des données</h2><p>Vos données sont conservées pendant une durée maximale de 3 ans à compter de votre dernière interaction avec Fab Sourcing. Vous pouvez demander leur suppression à tout moment.</p><h2>Partage des données</h2><p>Fab Sourcing ne vend, ne loue ni ne partage vos données personnelles avec des tiers, sauf obligation légale.</p><h2>Vos droits</h2><p>Conformément au RGPD, vous disposez d\'un droit d\'accès, de rectification, de suppression et d\'opposition concernant vos données personnelles. Pour exercer ces droits, contactez-nous à : tsudol.fabtec@yahoo.com</p><h2>Cookies</h2><p>Ce site n\'utilise pas de cookies publicitaires. Des cookies techniques strictement nécessaires au fonctionnement du site peuvent être utilisés.</p>\",\"en\":\"<h2>Data Collected</h2><p>When you submit the contact form, we collect the following information: name, company (optional), email address, phone number (optional), and your message. This data is used solely to respond to your enquiry.</p><h2>Data Retention</h2><p>Your data is retained for a maximum of 3 years from your last interaction with Fab Sourcing. You may request deletion at any time.</p><h2>Data Sharing</h2><p>Fab Sourcing does not sell, rent or share your personal data with third parties, except where required by law.</p><h2>Your Rights</h2><p>In accordance with the GDPR, you have the right to access, rectify, delete and object to the processing of your personal data. To exercise these rights, contact us at: tsudol.fabtec@yahoo.com</p><h2>Cookies</h2><p>This site does not use advertising cookies. Strictly necessary technical cookies required for site operation may be used.</p>\"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'politique-de-confidentialite', 1, NULL, '2026-05-13 19:46:27', '2026-05-14 18:09:02', NULL, '{\"fr\":\"Politique de confidentialité | Fab Sourcing\",\"en\":\"Privacy Policy | Fab Sourcing\"}', '{\"fr\":\"Politique de confidentialité et gestion des données personnelles — fab-sourcing.fr.\",\"en\":\"Privacy policy and personal data management — fab-sourcing.fr.\"}'),
(9, '{\"fr\":\"Accueil\",\"en\":\"Home\"}', '{\"fr\":\"<p></p>\",\"en\":\"<p></p>\"}', '{\"en\": \"Bulgaria\\r\\n& Romania — \\r\\nYour reliable\\r\\npartner in\\r\\nmetalworking\", \"fr\": \"Bulgarie\\r\\n& Roumanie –\\r\\nVotre partenaire\\r\\nfiable en\\r\\nmétallurgie\"}', '{\"en\": \"We support French companies in optimising their industrial production through outsourcing solutions in Bulgaria and Romania.\", \"fr\": \"Nous accompagnons les entreprises françaises dans l’optimisation de leur production industrielle grâce à des solutions d’outsourcing en Bulgarie et en Roumanie.\"}', '{\"en\": \"Specialised in metalworking and custom metal fabrication, we provide access to a network of qualified factories able to produce to demanding European standards.\", \"fr\": \"Spécialisés dans la métallerie et la fabrication métallique sur mesure, nous mettons à votre disposition un réseau d’usines qualifiées, capables de produire avec des standards européens exigeants.\"}', '{\"en\": \"Why Eastern Europe\", \"fr\": \"Pourquoi l\'Europe de l\'Est\"}', '{\"en\": \"European quality, controlled costs\", \"fr\": \"Qualité européenne, coûts maîtrisés\"}', NULL, '{\"en\": \"Partner workshop network\", \"fr\": \"Réseau d\'usines partenaires\"}', '30–50%', '{\"en\": \"savings\", \"fr\": \"d\'économies\"}', '3–4', '{\"en\": \"days to France\", \"fr\": \"jours vers la France\"}', '{\"en\": \"40–60% lower costs\", \"fr\": \"Coûts réduits de 40 à 60 %\"}', '{\"en\": \"Labour costs 40–60% lower than in France or Germany, with no compromise on quality.\", \"fr\": \"Coûts de main-d\'œuvre 40–60 % inférieurs à la France ou l\'Allemagne, sans compromis sur la qualité.\"}', '{\"en\": \"Same European standards\", \"fr\": \"Mêmes normes européennes\"}', '{\"en\": \"Partner workshops meet the same European requirements as their French counterparts: CE compliance, traceability, quality and on-time delivery.\", \"fr\": \"Les ateliers partenaires respectent les mêmes exigences européennes que leurs homologues français : conformité CE, traçabilité, qualité et respect des délais.\"}', '{\"en\": \"Fast logistics\", \"fr\": \"Logistique rapide\"}', '{\"en\": \"Optimised transport to France in 3–4 days by road. Easy access for on-site quality checks.\", \"fr\": \"Transport optimisé vers la France en 3 à 4 jours par route. Accessibilité facilitée pour les contrôles qualité sur site.\"}', '{\"en\": \"Shared EU regulatory framework\", \"fr\": \"Cadre réglementaire UE commun\"}', '{\"en\": \"EU member state: IP protection, CE compliance, legal framework harmonised with France.\", \"fr\": \"État membre de l\'UE : propriété intellectuelle protégée, conformité CE, cadre juridique harmonisé avec la France.\"}', 'home', 1, 'pages/cEXurwU9USQZjjuK6nRfckXhISNLfhymhS3h0yEh.png', '2026-05-14 06:56:54', '2026-05-15 08:23:49', 1, '{\"fr\":\"Outsourcing industriel en Bulgarie & Roumanie | Métallerie & fabrication acier\",\"en\":\"Industrial Outsourcing in Bulgaria & Romania | Metalwork & Steel Fabrication\"}', '{\"fr\":\"Externalisez votre production industrielle en Europe de l\'Est. Métallerie, structures acier, escaliers, garde-corps. Qualité UE, coûts réduits.\",\"en\":\"Outsource your industrial production to Eastern Europe. Metalwork, steel structures, stairs, railings. EU-certified quality, reduced costs.\"}'),
(10, '{\"fr\":\"Blog\",\"en\":\"Blog\"}', '{\"en\":\"\"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'blog', 1, NULL, '2026-05-14 09:04:19', '2026-05-14 09:04:19', 7, '{\"fr\":\"Blog industriel — Fab Sourcing\",\"en\":\"Industrial Blog — Fab Sourcing\"}', '{\"fr\":\"Conseils, études de cas et actualités sur la sous-traitance industrielle en Europe de l\'Est.\",\"en\":\"Advice, case studies and news on industrial subcontracting in Eastern Europe.\"}');

INSERT INTO `product_categories` (`id`, `slug`, `slug_en`, `name`, `description`, `long_description`, `icon`, `image`, `sort_order`, `published`, `featured`, `featured_order`, `created_at`, `updated_at`) VALUES
(1, 'structures-metalliques', 'steel-structure-metalwork', '{\"en\": \"Metal structures\", \"fr\": \"Structures métalliques\"}', '{\"en\": \"Frameworks, custom structures and welded assemblies for industrial buildings.\", \"fr\": \"Charpentes, structures spécifiques et pièces mécano-soudées pour bâtiments industriels.\"}', NULL, NULL, 'categories/structures-metalliques-1778834703.jpg', 3, 1, 1, 3, '2026-05-13 19:01:00', '2026-05-17 14:13:27'),
(2, 'escaliers-metalliques', 'custom-metal-stairs', '{\"en\": \"Metal stairs\", \"fr\": \"Escaliers métalliques\"}', '{\"en\": \"Industrial and architectural steel stairs, indoor and outdoor, to European standards.\", \"fr\": \"Escaliers industriels et architecturaux en acier, intérieur et extérieur, aux normes européennes.\"}', NULL, NULL, 'categories/escaliers-metalliques-1778834541.jpg', 1, 1, 1, 1, '2026-05-13 19:01:00', '2026-05-17 14:13:27'),
(3, 'garde-corps-mains-courantes', 'stainless-steel-railings-handrails', '{\"en\": \"Railings and handrails\", \"fr\": \"Garde-corps et mains courantes\"}', '{\"en\": \"Stainless steel, steel and aluminium solutions for safety and design, made to measure.\", \"fr\": \"Solutions en inox, acier et aluminium pour la sécurité et le design, sur mesure.\"}', NULL, NULL, 'categories/garde-corps-mains-courantes-1778834629.jpg', 2, 1, 1, 2, '2026-05-13 19:01:00', '2026-05-17 14:13:27'),
(4, 'menuiseries-metalliques', 'metal-windows-doors-joinery', '{\"en\": \"Metal joinery\", \"fr\": \"Menuiseries métalliques\"}', '{\"en\": \"Armoured doors, industrial-style glazed bays and high-performance steel windows.\", \"fr\": \"Portes blindées, baies vitrées style industriel et fenêtres acier haute performance.\"}', NULL, NULL, 'categories/menuiseries-metalliques-1778835224.png', 6, 1, 0, NULL, '2026-05-13 19:01:00', '2026-05-17 14:13:27'),
(5, 'bardages-facades', 'industrial-metal-cladding-facade', '{\"en\": \"Cladding and facades\", \"fr\": \"Bardages et façades\"}', '{\"en\": \"Architectural cladding in steel, aluminium, zinc or stainless steel, choice of finishes.\", \"fr\": \"Revêtements architecturaux en acier, aluminium, zinc ou inox, finitions au choix.\"}', NULL, NULL, NULL, 7, 1, 0, NULL, '2026-05-13 19:01:00', '2026-05-17 14:13:27'),
(6, 'bacs-retention-shelters', 'workshop-glass-roof-partition', '{\"en\": \"Retention basins and shelters\", \"fr\": \"Bacs de rétention et shelters\"}', '{\"en\": \"CE-standard steel retention basins, technical shelters and metal enclosures.\", \"fr\": \"Bacs de rétention acier aux normes CE, shelters techniques et abris métalliques.\"}', NULL, NULL, 'categories/bacs-retention-shelters-1778834963.png', 5, 1, 1, 5, '2026-05-13 19:01:00', '2026-05-17 14:13:27'),
(7, 'portails-clotures', 'custom-steel-gate-fence', '{\"en\": \"Gates and fences\", \"fr\": \"Portails et clôtures\"}', '{\"en\": \"Motorised gates and fences in rigid panels, wrought iron or perforated sheet.\", \"fr\": \"Portails motorisés et clôtures en panneaux rigides, fer forgé ou tôle perforée.\"}', NULL, NULL, NULL, 8, 1, 0, NULL, '2026-05-13 19:01:00', '2026-05-17 14:13:27'),
(8, 'terrasses-balcons', 'terrace-balcony-outdoor-railing', '{\"en\": \"Metal terraces and balconies\", \"fr\": \"Terrasses et balcons métalliques\"}', '{\"en\": \"Suspended terraces and prefabricated balconies in IPN/HEA steel structure.\", \"fr\": \"Terrasses suspendues et balcons préfabriqués en structure acier IPN/HEA.\"}', NULL, NULL, NULL, 9, 1, 0, NULL, '2026-05-13 19:01:00', '2026-05-17 14:13:27'),
(9, 'racks-equipements-industriels', 'industrial-rack-storage-shelter', '{\"en\": \"Industrial racks and equipment\", \"fr\": \"Racks et équipements industriels\"}', '{\"en\": \"Storage racks and custom metal logistics solutions for warehouses.\", \"fr\": \"Racks de stockage et solutions logistiques métalliques sur mesure pour entrepôts.\"}', NULL, NULL, 'categories/racks-equipements-industriels-1778834906.png', 4, 1, 1, 4, '2026-05-13 19:01:00', '2026-05-17 14:13:27');

INSERT INTO `products` (`id`, `product_category_id`, `slug`, `slug_en`, `name`, `short_description`, `full_description`, `features`, `materials`, `specifications`, `main_image`, `gallery_images`, `tag_number`, `sort_order`, `published`, `featured`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES
(1, 1, 'charpente-metallique-industrielle', 'industrial-steel-frame', '{\"en\": \"Industrial Steel Frame\", \"fr\": \"Charpente métallique industrielle\"}', '{\"en\": \"Load-bearing steel frame for warehouses, workshops and industrial buildings, manufactured to drawings and applicable European standards.\", \"fr\": \"Structure portante acier pour entrepôts, ateliers et bâtiments industriels, fabriquée selon plans et normes européennes en vigueur.\"}', '{\"en\": \"<p>Our industrial steel frames are engineered to meet the most demanding structural requirements. Fabricated in S235 or S355 grade steel to calculated load specifications, they incorporate columns, IPE/HEA beams, bracing and base plates. Each assembly is delivered shot-blasted and primed, ready for topcoat application on site. Our partner workshops in Bulgaria ensure compliance with European standards and full material traceability.</p>\", \"fr\": \"<p>Nos charpentes métalliques industrielles sont conçues pour répondre aux exigences structurelles les plus sévères. Fabriquées en acier S235 ou S355 selon les charges calculées, elles intègrent poteaux, poutres IPE/HEA, contreventements et platines d\'ancrage. Chaque ensemble est livré sablé et imprimé, prêt pour l\'application de la couche de finition sur chantier. Nos ateliers partenaires en Bulgarie assurent la conformité aux normes européennes et la traçabilité complète des matériaux.</p>\"}', '{\"en\": \"<ul><li>S235 / S355 steel to structural calculations</li><li>European standard compliance</li><li>Full material traceability</li><li>Delivered shot-blasted + anti-corrosion primer</li><li>Base plates, anchor bolts and fixings included</li></ul>\", \"fr\": \"<ul><li>Acier S235 / S355 selon calcul</li><li>Conformité normes européennes</li><li>Traçabilité matière complète</li><li>Livraison sablée + primaire anticorrosion</li><li>Platines, goujons et boulonnerie inclus</li></ul>\"}', '{\"en\": \"Structural steel S235JR / S355JR, grade 8.8 bolts, A42 base plates.\", \"fr\": \"Acier de construction S235JR / S355JR, boulonnerie 8.8, platines A42.\"}', '{\"en\": \"Spans up to 30 m. Ridge height up to 12 m. Tight fabrication tolerances. Finish: shot-blast SA 2½ + 60 µm epoxy primer.\", \"fr\": \"Portées jusqu\'à 30 m. Hauteur sous faîtage jusqu\'à 12 m. Tolérances serrées. Finition : grenaillage SA 2½ + primaire époxy 60 µm.\"}', NULL, NULL, NULL, 1, 1, 1, NULL, NULL, '2026-05-14 18:09:02', '2026-05-15 07:40:30'),
(2, 1, 'ossature-acier-batiment', 'steel-building-structure', '{\"en\": \"Steel Building Structure\", \"fr\": \"Ossature acier pour bâtiment\"}', '{\"en\": \"Secondary steel framework for cladding, roofing or floor systems — cold-formed sections, rails and studs to specification.\", \"fr\": \"Ossature acier secondaire pour bardage, toiture ou plancher — profilés à froid, rails et montants sur mesure.\"}', '{\"en\": \"<p>The essential complement to the primary frame, secondary steel structure provides the support for façade, roofing and floor elements. Z, C, omega sections and galvanised steel rails are custom-fabricated to architect\'s drawings. Our workshops handle cutting, drilling and bending to tight tolerances for rapid site installation.</p>\", \"fr\": \"<p>Complément indispensable de la charpente principale, l\'ossature secondaire en acier assure le support des éléments de façade, de toiture et de plancher. Profilés Z, C, oméga et rails en acier galvanisé sont fabriqués sur mesure selon les plans d\'architecte. Nos ateliers assurent la découpe, le perçage et le pliage avec précision, pour une pose rapide sur chantier.</p>\"}', '{\"en\": \"<ul><li>Galvanised Z, C, omega sections</li><li>CNC cutting and drilling</li><li>A2/A4 bolted assembly</li><li>Workshop drawings supplied</li></ul>\", \"fr\": \"<ul><li>Profilés Z, C, oméga galvanisés</li><li>Découpe et perçage CNC</li><li>Assemblage par boulonnerie A2/A4</li><li>Plans d\'atelier fournis</li></ul>\"}', '{\"en\": \"Z275 or Z350 galvanised steel.\", \"fr\": \"Acier galvanisé Z275 ou Z350.\"}', '{\"en\": \"Thicknesses 1.5 to 4 mm. Lengths up to 12 m. Hot-dip galvanised or pre-painted.\", \"fr\": \"Épaisseurs 1,5 à 4 mm. Longueurs jusqu\'à 12 m. Galvanisation à chaud ou prélaqué.\"}', NULL, NULL, NULL, 2, 1, 0, NULL, NULL, '2026-05-14 18:09:02', '2026-05-14 18:09:02'),
(3, 1, 'mezzanine-industrielle-acier', 'industrial-steel-mezzanine', '{\"en\": \"Industrial Steel Mezzanine\", \"fr\": \"Mezzanine industrielle acier\"}', '{\"en\": \"Self-supporting steel mezzanine for warehouse or workshop — open-grid or chequerplate floor, integrated railing.\", \"fr\": \"Mezzanine acier autoportante pour entrepôt ou atelier — plancher caillebotis ou tôle larmée, garde-corps intégré.\"}', '{\"en\": \"<p>Our industrial mezzanines double the usable floor area of a warehouse without extending the building. The self-supporting steel structure (HEB columns, IPE beams, joists) is sized for live loads from 200 to 750 kg/m². The floor deck is open-grid galvanised grating or chequerplate, depending on use. The system includes an access stair and compliant safety railings.</p>\", \"fr\": \"<p>Nos mezzanines industrielles permettent de doubler la surface utile d\'un entrepôt sans extension du bâtiment. La structure autoportante en acier (poteaux HEB, poutres IPE, solives) est dimensionnée pour des charges d\'exploitation de 200 à 750 kg/m². Le plancher est en caillebotis galvanisé ou tôle larmée selon l\'usage. Le système comprend un escalier d\'accès et des garde-corps réglementaires.</p>\"}', '{\"en\": \"<ul><li>Live load 200–750 kg/m²</li><li>Open-grid or chequerplate deck</li><li>Stair and safety railings included</li><li>Bolted base plate floor anchorage</li><li>Structural calculation provided</li></ul>\", \"fr\": \"<ul><li>Charge utile 200–750 kg/m²</li><li>Plancher caillebotis ou tôle larmée</li><li>Escalier et garde-corps inclus</li><li>Ancrage au sol par platines boulonnées</li><li>Calcul de structure fourni</li></ul>\"}', '{\"en\": \"S235 / S355 steel, 30×100 galvanised open-grid grating.\", \"fr\": \"Acier S235 / S355, caillebotis galvanisé 30×100.\"}', '{\"en\": \"Minimum 2.50 m clear height below mezzanine. Floor area up to 1,000 m² per level.\", \"fr\": \"Hauteur libre sous mezzanine 2,50 m minimum. Surface jusqu\'à 1 000 m² par niveau.\"}', NULL, NULL, NULL, 3, 1, 0, NULL, NULL, '2026-05-14 18:09:02', '2026-05-14 18:09:02'),
(4, 2, 'escalier-helicoidal-acier', 'helical-steel-staircase', '{\"en\": \"Helical Steel Staircase\", \"fr\": \"Escalier hélicoïdal acier\"}', '{\"en\": \"Custom helical steel staircase — central column or curved strings, chequerplate or timber treads.\", \"fr\": \"Escalier hélicoïdal en acier sur mesure — structure centrale ou limons courbes, marches en tôle larmée ou bois.\"}', '{\"en\": \"<p>The helical steel staircase combines contemporary aesthetics with a compact footprint. The structure — in raw, powder-coated or galvanised steel — is custom-fabricated to the required diameter and floor-to-floor height. Treads are available in chequerplate, open-grid grating, glass or solid timber. Each staircase is delivered as a pre-assembled kit for straightforward on-site installation. Compliant with NF P 01-013.</p>\", \"fr\": \"<p>L\'escalier hélicoïdal acier allie esthétique contemporaine et compacité. La structure en acier brut, laqué ou galvanisé est fabriquée sur mesure selon le diamètre souhaité et la hauteur à franchir. Les marches peuvent être en tôle larmée, caillebotis, verre ou bois massif. Chaque escalier est livré en kit prémonté pour faciliter l\'installation sur chantier. Conformité NF P 01-013.</p>\"}', '{\"en\": \"<ul><li>Diameter 120 to 200 cm</li><li>Chequerplate, open-grid, timber or glass treads</li><li>RAL powder coat or galvanised finish</li><li>Pre-assembled kit delivery</li><li>NF P 01-013 compliant</li></ul>\", \"fr\": \"<ul><li>Diamètre 120 à 200 cm</li><li>Marches tôle, caillebotis, bois ou verre</li><li>Finition laquée RAL ou galvanisée</li><li>Kit prémonté en atelier</li><li>Conformité NF P 01-013</li></ul>\"}', '{\"en\": \"S235 steel, option 304/316 stainless steel.\", \"fr\": \"Acier S235, option inox 304/316.\"}', '{\"en\": \"Floor-to-floor height up to 5 m. Per-tread load 200 kg. Anti-slip nosing.\", \"fr\": \"Hauteur à franchir jusqu\'à 5 m. Charge par marche 200 kg. Nez de marche antidérapant.\"}', NULL, NULL, NULL, 1, 1, 1, NULL, NULL, '2026-05-14 18:09:02', '2026-05-14 18:09:02'),
(5, 2, 'escalier-droit-industriel', 'straight-industrial-staircase', '{\"en\": \"Straight Industrial Staircase\", \"fr\": \"Escalier droit industriel\"}', '{\"en\": \"Straight steel staircase for industrial use — UPN stringers, open-grid treads, ERP compliant.\", \"fr\": \"Escalier droit acier pour usage industriel — limons UPN, marches caillebotis, conformité ERP.\"}', '{\"en\": \"<p>Designed for demanding industrial environments, the straight steel staircase delivers robustness and longevity. Stringers are UPN section or welded flat plate; treads are 30×100 galvanised open-grid grating with anti-slip nosing. The assembly is delivered shot-blasted and primed, or hot-dip galvanised depending on the service environment. Integrated handrail compliant with labour code requirements.</p>\", \"fr\": \"<p>Conçu pour les environnements industriels exigeants, l\'escalier droit en acier offre robustesse et durabilité. Les limons sont en profilé UPN ou plat soudé, les marches en caillebotis galvanisé 30×100 avec nez antidérapant. L\'ensemble est livré grenaillé et primé, ou galvanisé à chaud selon l\'environnement d\'utilisation. Garde-corps intégré conforme au code du travail.</p>\"}', '{\"en\": \"<ul><li>UPN or welded flat-plate stringers</li><li>Galvanised open-grid treads</li><li>Labour-code-compliant handrail</li><li>Hot-dip galvanising available</li><li>Intermediate landings on request</li></ul>\", \"fr\": \"<ul><li>Limons UPN ou plat soudé</li><li>Marches caillebotis galvanisé</li><li>Garde-corps code du travail</li><li>Galvanisation à chaud disponible</li><li>Paliers intermédiaires sur demande</li></ul>\"}', '{\"en\": \"S235 steel, Z275 galvanising or powder coating.\", \"fr\": \"Acier S235, galvanisation Z275 ou thermolaquage.\"}', '{\"en\": \"Width 80 to 120 cm. Pitch 30° to 45°. Live load 400 kg/m².\", \"fr\": \"Largeur 80 à 120 cm. Inclinaison 30° à 45°. Charge 400 kg/m².\"}', NULL, NULL, NULL, 2, 1, 0, NULL, NULL, '2026-05-14 18:09:02', '2026-05-14 18:09:02'),
(6, 2, 'escalier-cremaillere-design', 'design-sawtooth-staircase', '{\"en\": \"Design Sawtooth Staircase\", \"fr\": \"Escalier crémaillère design\"}', '{\"en\": \"Steel sawtooth staircase with central or side stringer — timber or metal treads, clean minimalist aesthetic.\", \"fr\": \"Escalier crémaillère acier à limon central ou latéral — marches bois ou métal, esthétique épurée.\"}', '{\"en\": \"<p>The sawtooth staircase — with its central or side spine stringer — is the defining feature of contemporary interiors and industrial lofts. The flat-plate or square-tube steel stringer is precision-cut and welded to create an airy silhouette. Treads in solid oak, reconstituted concrete or powder-coated steel complete the design. Each piece is custom-fabricated and delivered ready to install.</p>\", \"fr\": \"<p>L\'escalier crémaillère, ou escalier à limon central, est la référence des intérieurs contemporains et des lofts industriels. Le limon en acier plat ou tube carré est découpé et soudé avec soin pour créer une silhouette aérienne. Les marches en chêne massif, béton reconstitué ou acier laqué viennent compléter le design. Chaque pièce est fabriquée sur mesure et livrée prête à poser.</p>\"}', '{\"en\": \"<ul><li>Flat-plate or square-tube steel stringer</li><li>Oak, concrete or powder-coated treads</li><li>Raw, RAL powder coat or patinated finish</li><li>Glass or cable railing available</li><li>3D drawings provided before fabrication</li></ul>\", \"fr\": \"<ul><li>Limon plat ou tube carré acier</li><li>Marches chêne, béton ou acier laqué</li><li>Finition brute, laquée RAL ou patinée</li><li>Garde-corps verre ou câbles disponible</li><li>Plans 3D fournis avant fabrication</li></ul>\"}', '{\"en\": \"S235 steel powder-coated or raw + oak / concrete treads.\", \"fr\": \"Acier S235 laqué ou brut + marches chêne/béton.\"}', '{\"en\": \"Open or closed risers. Width 80–120 cm. Integrated anti-slip tread nosing.\", \"fr\": \"Contre-marches ouvertes ou fermées. Largeur 80–120 cm. Nez de marche anti-glisse intégré.\"}', NULL, NULL, NULL, 3, 1, 0, NULL, NULL, '2026-05-14 18:09:02', '2026-05-14 18:09:02'),
(7, 3, 'garde-corps-inox-304', 'stainless-steel-railing-304', '{\"en\": \"Stainless Steel Railing 304\", \"fr\": \"Garde-corps inox 304\"}', '{\"en\": \"Brushed 304 stainless steel railing — cable, glass or bar infill, for indoor and outdoor use.\", \"fr\": \"Garde-corps en inox 304 brossé — remplissage câbles, vitrage ou barreaux, intérieur et extérieur.\"}', '{\"en\": \"<p>The 304 stainless steel railing is the benchmark for moisture-exposed environments and design interiors. The Ø42.4 round-tube handrail and Ø48.3 posts are assembled with collars or ground-down TIG welds. Ø8 stainless cable infill or 10.76 mm laminated safety glass provides a light, open aesthetic while meeting NF P 01-012 requirements. Supplied as a kit or installed, depending on site configuration.</p>\", \"fr\": \"<p>Le garde-corps inox 304 est la référence pour les environnements exposés à l\'humidité et les espaces intérieurs design. La main courante tube rond Ø42,4 et les poteaux Ø48,3 sont assemblés par colliers ou soudures TIG meulées. Le remplissage câble inox Ø8 ou vitrage feuilleté sécurit 10,76 mm offre légèreté visuelle et conformité NF P 01-012. Livré en kits ou posé, selon la configuration du chantier.</p>\"}', '{\"en\": \"<ul><li>Brushed or mirror-polished 304 stainless</li><li>Cable, glass or bar infill</li><li>NF P 01-012 compliant</li><li>Base plate, glass clamp or core-drilled fixing</li><li>Height 1.00 m or 1.10 m to specification</li></ul>\", \"fr\": \"<ul><li>Inox 304 brossé ou poli miroir</li><li>Remplissage câble, verre ou barreaux</li><li>Conforme NF P 01-012</li><li>Fixation platine, pince verre ou poteau encastré</li><li>Hauteur 1,00 m ou 1,10 m selon usage</li></ul>\"}', '{\"en\": \"AISI 304 stainless steel or 316 for marine environments.\", \"fr\": \"Inox AISI 304 ou 316 pour environnement marin.\"}', '{\"en\": \"Height 1.00–1.10 m. Resistance 1 kN/m. Ø8 mm pre-tensioned cables, max 120 mm spacing.\", \"fr\": \"Hauteur 1,00–1,10 m. Résistance 1 kN/m. Câbles pretendus Ø8 mm, espacement max 120 mm.\"}', NULL, NULL, NULL, 1, 1, 1, NULL, NULL, '2026-05-14 18:09:02', '2026-05-14 18:09:02'),
(8, 3, 'main-courante-acier-laque', 'powder-coated-steel-handrail', '{\"en\": \"Powder-Coated Steel Handrail\", \"fr\": \"Main courante acier laqué\"}', '{\"en\": \"Powder-coated steel handrail and railing in RAL finish — industrial design, durable coating, rapid assembly.\", \"fr\": \"Main courante et garde-corps acier thermolaqué RAL — design industriel, finition durable, montage rapide.\"}', '{\"en\": \"<p>The powder-coated steel railing is the natural choice for budget-conscious projects that refuse to compromise on aesthetics. Round or square posts, flat or profiled handrail, solid or perforated infill — the combinations are endless. The powder coating applied in our workshops is UV, impact and temperature-change resistant. Available across the full RAL range or to a custom colour.</p>\", \"fr\": \"<p>Le garde-corps acier thermolaqué s\'impose dans les projets à budget maîtrisé sans sacrifier l\'esthétique. Poteaux ronds ou carrés, main courante plate ou profilée, remplissage lisse ou ajouré : les combinaisons sont infinies. Le thermolaquage appliqué par nos ateliers résiste aux UV, aux chocs et aux variations de température. Disponible dans toute la gamme RAL ou teinte spéciale.</p>\"}', '{\"en\": \"<ul><li>Round or square steel posts</li><li>RAL or custom colour powder coating</li><li>Bar, perforated or solid panel infill</li><li>Quality MIG welding</li><li>CE marking available</li></ul>\", \"fr\": \"<ul><li>Poteaux ronds ou carrés acier</li><li>Thermolaquage RAL ou teinte spéciale</li><li>Remplissage barreaux, tôle perforée ou lisse</li><li>Soudure MIG de qualité</li><li>Marquage CE disponible</li></ul>\"}', '{\"en\": \"S235 steel polyester powder coat. Coating thickness 60–80 µm.\", \"fr\": \"Acier S235 thermolaqué polyester. Épaisseur revêtement 60–80 µm.\"}', '{\"en\": \"Height 1.00–1.20 m. Post centres max 1.50 m. Resistance 0.5–1 kN/m.\", \"fr\": \"Hauteur 1,00–1,20 m. Entraxe poteaux max 1,50 m. Résistance 0,5–1 kN/m.\"}', NULL, NULL, NULL, 2, 1, 0, NULL, NULL, '2026-05-14 18:09:02', '2026-05-15 07:40:30'),
(9, 3, 'garde-corps-verre-metal', 'glass-metal-railing', '{\"en\": \"Glass and Metal Railing\", \"fr\": \"Garde-corps verre et métal\"}', '{\"en\": \"Laminated safety glass infill railing — steel or stainless structure, unobstructed sightlines.\", \"fr\": \"Garde-corps à remplissage vitrage feuilleté sécurit — structure acier ou inox, vue dégagée garantie.\"}', '{\"en\": \"<p>The glass and metal railing is the most elegant solution for preserving views while ensuring safety. The structure can be in black powder-coated steel or brushed stainless. Glass is 10.76 mm or 12.76 mm laminated safety glazing, selected to height and load requirements. Fixings are stainless clamps or recessed aluminium profiles. Ideal for terraces, mezzanines and high-specification interior partitions.</p>\", \"fr\": \"<p>Le garde-corps verre et métal est la solution la plus élégante pour préserver les vues tout en assurant la sécurité. La structure peut être en acier laqué noir ou en inox brossé. Le vitrage est en verre feuilleté sécurit 10,76 mm ou 12,76 mm selon la hauteur et la charge. La fixation s\'effectue par pinces inox ou profilés aluminium encastrés. Idéal pour les terrasses, mezzanines et séparations intérieures haut de gamme.</p>\"}', '{\"en\": \"<ul><li>10.76 or 12.76 mm laminated safety glass</li><li>Powder-coated steel or 304/316 stainless structure</li><li>Glass clamps or recessed profile</li><li>Flat or round-tube handrail</li><li>NF P 01-012 compliant</li></ul>\", \"fr\": \"<ul><li>Verre feuilleté sécurit 10,76 ou 12,76 mm</li><li>Structure acier laqué ou inox 304/316</li><li>Pinces verre ou profilé encastré</li><li>Main courante plate ou ronde</li><li>Conforme NF P 01-012</li></ul>\"}', '{\"en\": \"VSG laminated glass. S235 steel or 304 stainless structure.\", \"fr\": \"Verre feuilleté VSG. Structure acier S235 ou inox 304.\"}', '{\"en\": \"Height 1.00–1.10 m. Horizontal resistance 1 kN/m. Max glass panel 1.20×1.00 m.\", \"fr\": \"Hauteur 1,00–1,10 m. Résistance horizontale 1 kN/m. Panneaux verre max 1,20×1,00 m.\"}', NULL, NULL, NULL, 3, 1, 0, NULL, NULL, '2026-05-14 18:09:02', '2026-05-15 07:40:30'),
(10, 4, 'porte-entree-acier-blindee', 'security-steel-entrance-door', '{\"en\": \"Security Steel Entrance Door\", \"fr\": \"Porte d\'entrée acier blindée\"}', '{\"en\": \"Custom security steel entrance door — BP2/BP3 burglary resistance, thermal and acoustic insulation.\", \"fr\": \"Porte d\'entrée acier blindée sur mesure — résistance effraction BP2/BP3, isolation thermique et acoustique.\"}', '{\"en\": \"<p>Our security steel entrance doors combine safety, insulation and design. The 2 mm steel leaf is reinforced by an internal cold-formed section frame with mineral wool infill. Multi-point locking and high-security hardware are factory-fitted. Finish in RAL powder coat or wood-effect. BP2 and BP3 burglary resistance compliant depending on configuration.</p>\", \"fr\": \"<p>Nos portes d\'entrée acier blindées combinent sécurité, isolation et design. Le vantail acier 2 mm est renforcé par une structure intérieure en profilés à froid avec remplissage laine de roche. La serrurerie multipoints et la quincaillerie de haute sécurité sont intégrées en usine. Finition thermolaquage RAL ou aspect bois. Conforme aux exigences BP2 et BP3 selon configuration.</p>\"}', '{\"en\": \"<ul><li>2 mm steel + internal armature</li><li>BP2 / BP3 resistance rating</li><li>A2P-certified multi-point lock</li><li>Sound insulation Rw ≥ 38 dB</li><li>Thermal-break threshold</li></ul>\", \"fr\": \"<ul><li>Acier 2 mm + armature interne</li><li>Résistance BP2 / BP3</li><li>Serrure multipoints certifiée A2P</li><li>Isolation Rw ≥ 38 dB</li><li>Seuil à rupture de pont thermique</li></ul>\"}', '{\"en\": \"2 mm galvanised steel, 40 mm mineral wool, EPDM seals.\", \"fr\": \"Acier galvanisé 2 mm, laine de roche 40 mm, joints EPDM.\"}', '{\"en\": \"Standard 90×215 cm or custom size. Weight 80–120 kg. AEV rating on request.\", \"fr\": \"Dimensions standard 90×215 cm ou sur mesure. Poids 80–120 kg. Classement AEV sur demande.\"}', NULL, NULL, NULL, 1, 1, 0, NULL, NULL, '2026-05-14 18:09:02', '2026-05-14 18:09:02'),
(11, 4, 'baie-vitree-acier-rupture-pont-thermique', 'steel-glazed-door-thermal-break', '{\"en\": \"Steel Glazed Opening with Thermal Break\", \"fr\": \"Baie vitrée acier à rupture de pont thermique\"}', '{\"en\": \"Sliding or fixed steel glazed opening with thermal-break profiles — argon double glazing, industrial design, RE2020 performance.\", \"fr\": \"Baie vitrée coulissante ou fixe en profilé acier RPT — double vitrage argon, design industriel, performance RE2020.\"}', '{\"en\": \"<p>The thermal-break steel profile glazed opening meets RE2020 regulatory requirements while preserving the industrial aesthetic of slim steel sections. Available as fixed, sliding or pocket-door, it accepts glazing units up to 44 mm (triple glazing). Ideal for house extensions, overhead glazing or design shopfronts.</p>\", \"fr\": \"<p>La baie vitrée en profilé acier à rupture de pont thermique répond aux exigences de la réglementation RE2020 tout en conservant l\'esthétique industrielle des profils acier fins. Disponible en version fixe, coulissante ou à galandage, elle accepte des vitrages jusqu\'à 44 mm (triple vitrage). Idéale pour les extensions de maison, les verrières de toit ou les fronts de boutique design.</p>\"}', '{\"en\": \"<ul><li>Steel RPT profile ≥ 10 mm</li><li>Double or triple glazing up to 44 mm</li><li>Uw ≤ 1.4 W/m².K</li><li>Sliding, fixed or pocket door</li><li>NF Window / CSTB certified</li></ul>\", \"fr\": \"<ul><li>Profilé acier RPT ≥ 10 mm</li><li>Double ou triple vitrage jusqu\'à 44 mm</li><li>Uw ≤ 1,4 W/m².K</li><li>Coulissant, fixe ou galandage</li><li>Certifié NF Fenêtre / CSTB</li></ul>\"}', '{\"en\": \"Thermal-break steel profile, 4/16/4 argon Low-E double glazing.\", \"fr\": \"Profilé acier RPT, vitrage double argon 4/16/4 Low-E.\"}', '{\"en\": \"Width up to 5 m, height up to 3 m. Standard RAL colours.\", \"fr\": \"Largeur jusqu\'à 5 m, hauteur jusqu\'à 3 m. Couleurs RAL standard.\"}', NULL, NULL, NULL, 2, 1, 1, NULL, NULL, '2026-05-14 18:09:02', '2026-05-14 18:09:02'),
(12, 4, 'pergola-bioclimatique-acier', 'bioclimatic-steel-pergola', '{\"en\": \"Bioclimatic Steel Pergola\", \"fr\": \"Pergola bioclimatique acier\"}', '{\"en\": \"Bioclimatic steel pergola with aluminium louvre blades — rain sensor, silent motor, full outdoor comfort.\", \"fr\": \"Pergola bioclimatique en acier galvanisé — lames orientables aluminium, capteur de pluie, moteur silencieux.\"}', '{\"en\": \"<p>The bioclimatic steel pergola is the ideal solution for a year-round covered terrace. The Ø80×80 mm galvanised steel load-bearing structure is fitted with motorised aluminium louvre blades, adjustable from 0° to 120°. A rain sensor automatically closes the louvres in wet weather. Integrated LED lighting and optional side closures complete the comfort of the space.</p>\", \"fr\": \"<p>La pergola bioclimatique acier est la solution idéale pour aménager une terrasse couverte à l\'année. La structure porteuse acier galvanisé Ø80×80 mm est habillée de lames aluminium orientables à 0°/120° motorisées. Un capteur de pluie ferme automatiquement les lames en cas d\'intempérie. L\'éclairage LED intégré et les options de fermetures latérales complètent le confort de l\'espace.</p>\"}', '{\"en\": \"<ul><li>Ø80×80 galvanised steel structure</li><li>Motorised aluminium louvres 0°–120°</li><li>Integrated rain sensor</li><li>Integrated LED option</li><li>Glass or fabric side closures option</li></ul>\", \"fr\": \"<ul><li>Structure acier galvanisé Ø80×80</li><li>Lames aluminium motorisées 0°–120°</li><li>Capteur pluie intégré</li><li>LED intégré option</li><li>Fermetures latérales verre ou toile option</li></ul>\"}', '{\"en\": \"Galvanised S235 steel structure, 6060 T5 aluminium louvres.\", \"fr\": \"Structure acier S235 galvanisé, lames aluminium 6060 T5.\"}', '{\"en\": \"Span up to 6 m. Depth up to 4 m. Snow load 75 kg/m².\", \"fr\": \"Portée jusqu\'à 6 m. Profondeur jusqu\'à 4 m. Charge neige 75 kg/m².\"}', NULL, NULL, NULL, 3, 1, 0, NULL, NULL, '2026-05-14 18:09:02', '2026-05-14 18:09:02'),
(13, 5, 'bardage-tole-perforee', 'perforated-metal-cladding', '{\"en\": \"Perforated Sheet Cladding\", \"fr\": \"Bardage tôle perforée\"}', '{\"en\": \"Perforated steel or aluminium façade cladding — custom design, parametric perforation pattern, natural ventilation.\", \"fr\": \"Bardage façade en tôle perforée acier ou aluminium — design sur mesure, perforation paramétrique, ventilation naturelle.\"}', '{\"en\": \"<p>Perforated sheet cladding provides a façade finish that is both functional and visually striking. The perforation pattern (round, square, oblong or bespoke motif) is fully customisable to create light effects and filtered views. Galvanised steel or aluminium sheet is folded and fixed to a secondary framework. Ideal for car parks, warehouses, public facilities and commercial buildings.</p>\", \"fr\": \"<p>Le bardage tôle perforée offre un habillage de façade à la fois fonctionnel et esthétique. La perforation est paramétrable (ronde, carrée, oblongue, sur motif) pour créer des effets de lumière et filtrer les vues. La tôle acier galvanisé ou aluminium est pliée et fixée sur une ossature secondaire. Idéal pour les parkings couverts, entrepôts, équipements publics et immeubles tertiaires.</p>\"}', '{\"en\": \"<ul><li>Round, square or bespoke perforation</li><li>Galvanised steel or aluminium sheet</li><li>RAL powder coat or anodised finish</li><li>Galvanised secondary framework</li><li>Integrated natural ventilation</li></ul>\", \"fr\": \"<ul><li>Perforation ronde, carrée ou sur motif</li><li>Tôle acier galvanisé ou aluminium</li><li>Thermolaquage RAL ou anodisation</li><li>Ossature secondaire acier galvanisé</li><li>Ventilation naturelle intégrée</li></ul>\"}', '{\"en\": \"1.5–3 mm galvanised steel or 2–4 mm aluminium sheet.\", \"fr\": \"Tôle acier galvanisé 1,5–3 mm ou aluminium 2–4 mm.\"}', '{\"en\": \"Panels up to 3×1.5 m. Perforation rate 20–60 %. RAL or 20 µm anodising finish.\", \"fr\": \"Panneaux jusqu\'à 3×1,5 m. Taux de perforation 20–60 %. Finition RAL ou anodisation 20 µm.\"}', NULL, NULL, NULL, 1, 1, 0, NULL, NULL, '2026-05-14 18:09:02', '2026-05-14 18:09:02'),
(14, 5, 'facade-corten', 'corten-steel-facade', '{\"en\": \"Corten Steel Façade\", \"fr\": \"Façade acier Corten\"}', '{\"en\": \"Self-weathering Corten steel cladding and façade — natural rust aesthetic, maintenance-free durability.\", \"fr\": \"Bardage et façade en acier Corten autopatinable — esthétique rouille naturelle, résistance sans entretien.\"}', '{\"en\": \"<p>Corten (weathering steel) develops a self-protecting oxide layer that halts corrosion and produces its characteristic rust-red appearance. Used as façade cladding, it requires zero paint and zero maintenance. Panels are waterjet- or laser-cut to create graphic effects. Widely used in contemporary architecture, museums and landmark buildings.</p>\", \"fr\": \"<p>L\'acier Corten (ou acier patinable) développe naturellement une couche d\'oxyde protectrice qui stoppe la corrosion et lui confère son aspect rouille caractéristique. Utilisé en bardage de façade, il nécessite zéro peinture et zéro entretien. Les panneaux sont découpés au jet d\'eau ou au laser pour créer des effets graphiques. Très utilisé en architecture contemporaine, musées et monuments.</p>\"}', '{\"en\": \"<ul><li>S355J2W+N weathering steel</li><li>Laser or waterjet cut</li><li>Zero paint, zero maintenance</li><li>50+ year durability in non-marine environments</li><li>Custom panel sizes</li></ul>\", \"fr\": \"<ul><li>Acier patinable S355J2W+N</li><li>Découpe laser ou jet d\'eau</li><li>Zéro peinture, zéro entretien</li><li>Durabilité 50+ ans en environnement non marin</li><li>Panneaux sur mesure</li></ul>\"}', '{\"en\": \"Weathering steel S355J2W (Corten A/B), 3–8 mm thickness.\", \"fr\": \"Acier patinable S355J2W (Corten A/B), épaisseur 3–8 mm.\"}', '{\"en\": \"Panels up to 3 m. Concealed or exposed fixing. Condensation run-off to be designed on roof applications.\", \"fr\": \"Panneaux jusqu\'à 3 m. Fixation invisible ou visible. Rejets de condensation à prévoir sur toiture.\"}', NULL, NULL, NULL, 2, 1, 1, NULL, NULL, '2026-05-14 18:09:02', '2026-05-14 18:09:02'),
(15, 5, 'bardage-zinc', 'zinc-wall-cladding', '{\"en\": \"Zinc Wall Cladding\", \"fr\": \"Bardage zinc\"}', '{\"en\": \"Natural or pre-patinated zinc wall cladding — batten, standing seam or fish-scale pattern, 80-year durability.\", \"fr\": \"Bardage façade zinc naturel ou prépatiné — tasseaux, bacs à joint debout ou écailles, durabilité 80 ans.\"}', '{\"en\": \"<p>Natural or pre-patinated zinc is a premium façade material combining lightness, elegance and longevity. Our workshops produce standing-seam panels, batten-fixed cladding or custom fish-scale tiles in natural finishes (anthracite, slate, blue-grey). Guaranteed service life exceeds 80 years in non-aggressive environments.</p>\", \"fr\": \"<p>Le zinc naturel ou prépatiné s\'impose comme un matériau de façade premium, alliant légèreté, élégance et longévité. Nos ateliers produisent des bacs à joint debout, des bardages à tasseaux, ou des écailles sur mesure dans les teintes naturelles (anthracite, ardoise, bleu-gris). La durée de vie garantie dépasse 80 ans en milieu non agressif.</p>\"}', '{\"en\": \"<ul><li>Natural or pre-patinated zinc (anthracite, slate)</li><li>Standing seam, batten or fish-scale</li><li>80+ year durability</li><li>Maintenance-free</li><li>100% recyclable</li></ul>\", \"fr\": \"<ul><li>Zinc naturel ou prépatiné (anthracite, ardoise)</li><li>Joint debout, tasseaux ou écailles</li><li>Durabilité 80+ ans</li><li>Entretien nul</li><li>Recyclable à 100 %</li></ul>\"}', '{\"en\": \"VMzinc® or Rheinzink® 0.7–1.0 mm.\", \"fr\": \"Zinc VMzinc® ou Rheinzink® 0,7–1,0 mm.\"}', '{\"en\": \"Strips up to 6 m. Finishes: natural, quartz, anthracite, slate. Roof or wall application.\", \"fr\": \"Lés jusqu\'à 6 m de long. Teintes : naturel, quartz, anthracite, ardoise. Pose en couverture ou façade.\"}', NULL, NULL, NULL, 3, 1, 0, NULL, NULL, '2026-05-14 18:09:02', '2026-05-14 18:09:02'),
(16, 6, 'verriere-atelier-interieure', 'indoor-workshop-glazed-roof', '{\"en\": \"Indoor Workshop Glazed Partition\", \"fr\": \"Verrière atelier intérieure\"}', '{\"en\": \"Indoor workshop-style glazed partition in slim steel profiles — authentic industrial look, single or laminated glass.\", \"fr\": \"Verrière atelier intérieure en profilé acier fin — style industriel authentique, vitrage simple ou feuilleté.\"}', '{\"en\": \"<p>The indoor workshop partition is the defining element of industrial style and contemporary loft interiors. Our 20×20 or 40×40 square-tube steel profiles, welded to create the characteristic grid, are glazed with clear, laminated or cathedral glass. Available as room divider, gable end or hinged door. Raw, slate paint or RAL powder-coat finish.</p>\", \"fr\": \"<p>La verrière atelier intérieure est l\'élément signature du style industriel et des lofts contemporains. Nos profilés acier tube carré 20×20 ou 40×40 soudés créent le quadrillage caractéristique, habillé de vitrage simple, feuilleté ou verre cathédrale. Disponible en cloison de séparation, pignon ou porte atelier. Finition brute, peinture ardoise ou laquage RAL.</p>\"}', '{\"en\": \"<ul><li>20×20 or 40×40 mm square tube profiles</li><li>Full-penetration TIG welding</li><li>4 mm clear or 6.38 mm laminated glass</li><li>Integrated hinged door option</li><li>Raw, slate or RAL finish</li></ul>\", \"fr\": \"<ul><li>Profilés tube carré 20×20 ou 40×40 mm</li><li>Soudure TIG pleine pénétration</li><li>Vitrage simple 4 mm ou feuilleté 6,38 mm</li><li>Porte atelier intégrée possible</li><li>Finition brute, ardoise ou RAL</li></ul>\"}', '{\"en\": \"Welded S235 square steel tube. Clear or laminated glass.\", \"fr\": \"Acier S235 tube carré soudé. Vitrage clair ou feuilleté.\"}', '{\"en\": \"Max height 3.5 m. Max width 6 m. Partition thickness 60–80 mm.\", \"fr\": \"Hauteur max 3,5 m. Largeur max 6 m. Épaisseur cloison 60–80 mm.\"}', NULL, NULL, NULL, 1, 1, 1, NULL, NULL, '2026-05-14 18:09:02', '2026-05-14 18:09:02'),
(17, 6, 'cloison-verre-style-industriel', 'industrial-glass-partition-wall', '{\"en\": \"Industrial-Style Glass Partition Wall\", \"fr\": \"Cloison verre style industriel\"}', '{\"en\": \"Fixed or demountable glass and metal partition — office or living space divider, acoustic rating Rw ≥ 38 dB.\", \"fr\": \"Cloison amovible ou fixe en verre et métal — séparation bureau ou espace de vie, acoustique Rw ≥ 38 dB.\"}', '{\"en\": \"<p>The industrial-style glass and metal partition divides spaces without enclosing them. The powder-coated aluminium or steel frame accepts 10.76 mm double laminated glass panels for Rw ≥ 38 dB acoustic performance. The demountable version adapts as needs evolve. Available with or without door, full-height or partial.</p>\", \"fr\": \"<p>La cloison verre et métal style industriel sépare les espaces sans les fermer. La structure aluminium ou acier thermolaqué reçoit des panneaux de verre double feuilleté 10,76 mm pour une isolation acoustique Rw ≥ 38 dB. La version amovible s\'adapte à l\'évolution des besoins. Disponible avec ou sans porte, en hauteur sol plafond ou partielle.</p>\"}', '{\"en\": \"<ul><li>10.76 mm double laminated glass</li><li>Acoustic rating Rw ≥ 38 dB</li><li>Fixed or demountable version</li><li>Full-height or partial height</li><li>Integrated door option</li></ul>\", \"fr\": \"<ul><li>Verre double feuilleté 10,76 mm</li><li>Isolation acoustique Rw ≥ 38 dB</li><li>Version fixe ou amovible</li><li>Hauteur sol-plafond ou partielle</li><li>Porte intégrée option</li></ul>\"}', '{\"en\": \"Powder-coated steel or aluminium frame. 10.76 mm PVB laminated glass.\", \"fr\": \"Cadre acier ou aluminium thermolaqué. Verre feuilleté PVB 10,76 mm.\"}', '{\"en\": \"Height up to 3.5 m. Module width 60–120 cm. EPDM acoustic seals.\", \"fr\": \"Hauteur jusqu\'à 3,5 m. Largeur modules 60–120 cm. Joints EPDM silence phonique.\"}', NULL, NULL, NULL, 2, 1, 0, NULL, NULL, '2026-05-14 18:09:02', '2026-05-14 18:09:02'),
(18, 7, 'portail-coulissant-motorise', 'motorised-sliding-gate', '{\"en\": \"Motorised Sliding Gate\", \"fr\": \"Portail coulissant motorisé\"}', '{\"en\": \"Motorised steel sliding gate — self-supporting or rail-guided, remote control, intercom and badge access option.\", \"fr\": \"Portail coulissant acier motorisé — autoportant ou sur rail, télécommande, interphone et badge option.\"}', '{\"en\": \"<p>The motorised sliding gate is the prime solution for private and industrial access points. The galvanised steel structure is filled with round bars, solid plate or lattice depending on the required security level. The integrated brushless motor delivers silent, rapid opening. Compatible with all access control systems (intercom, badge reader, remote control).</p>\", \"fr\": \"<p>Le portail coulissant motorisé est la solution reine pour les accès privés et industriels. La structure acier galvanisé est remplie de barreaux ronds, de tôle pleine ou de lattis selon le niveau de sécurité souhaité. Le moteur brushless intégré permet une ouverture silencieuse et rapide. Compatible avec tous les systèmes de contrôle d\'accès (interphone, badge, télécommande).</p>\"}', '{\"en\": \"<ul><li>Hot-dip galvanised steel structure</li><li>Silent brushless motor</li><li>Self-supporting or bottom-rail guided</li><li>Bar, solid plate or lattice infill</li><li>Access control compatible</li></ul>\", \"fr\": \"<ul><li>Structure acier galvanisé à chaud</li><li>Moteur brushless silencieux</li><li>Autoportant ou sur rail bas</li><li>Remplissage barreaux, tôle ou lattis</li><li>Compatible contrôle d\'accès</li></ul>\"}', '{\"en\": \"Hot-dip galvanised S235 steel + RAL powder coat.\", \"fr\": \"Acier S235 galvanisé à chaud + thermolaquage RAL.\"}', '{\"en\": \"Width up to 8 m. Weight up to 600 kg. Opening speed 0.2–0.4 m/s. IP44.\", \"fr\": \"Largeur jusqu\'à 8 m. Poids jusqu\'à 600 kg. Vitesse ouverture 0,2–0,4 m/s. IP44.\"}', NULL, NULL, NULL, 1, 1, 0, NULL, NULL, '2026-05-14 18:09:02', '2026-05-14 18:09:02'),
(19, 7, 'cloture-panneaux-rigides', 'rigid-panel-fence', '{\"en\": \"Galvanised Rigid Panel Fence\", \"fr\": \"Clôture panneaux rigides galvanisés\"}', '{\"en\": \"Galvanised and plastic-coated rigid steel panel fence — anti-climb, 25-year durability.\", \"fr\": \"Clôture panneaux rigides acier galvanisé et plastifiés — résistance anti-effraction, durabilité 25 ans.\"}', '{\"en\": \"<p>The galvanised rigid panel fence is the most widely used perimeter security solution for industrial, commercial and public sites. Ø5 mm welded wire panels are hot-dip galvanised and PVC-coated in green or anthracite. H60 or H80 steel posts are grouted or bolted depending on the substrate. Available in heights from 1.20 to 2.50 m.</p>\", \"fr\": \"<p>La clôture à panneaux rigides galvanisés est la solution de sécurité périmétrique la plus répandue pour les sites industriels, commerciaux et collectifs. Les panneaux en fil soudé Ø5 mm sont galvanisés à chaud et plastifiés vert ou anthracite. Les poteaux H60 ou H80 acier sont scellés ou bridés selon le type de sol. Disponible en hauteur 1,20 à 2,50 m.</p>\"}', '{\"en\": \"<ul><li>Ø5 mm galvanised + PVC-coated welded wire</li><li>Panels 2.50 m × 1.03 to 2.53 m</li><li>H60/H80 posts, grouted or bolted</li><li>Green 6005 or anthracite 7016 colour</li><li>NF EN 13200 certified</li></ul>\", \"fr\": \"<ul><li>Fil soudé Ø5 mm galvanisé + plastifié</li><li>Panneaux 2,50 m × 1,03 à 2,53 m</li><li>Poteaux H60/H80 scellés ou bridés</li><li>Couleur vert 6005 ou anthracite 7016</li><li>Certifié NF EN 13200</li></ul>\"}', '{\"en\": \"Z275 galvanised steel wire, 0.5 mm PVC coating.\", \"fr\": \"Fil acier Z275 galvanisé, plastifié PVC 0,5 mm.\"}', '{\"en\": \"Height 1.20–2.50 m. Mesh 200×50 mm. Resistance 1 kN/m.\", \"fr\": \"Hauteur 1,20–2,50 m. Maille 200×50 mm. Résistance 1 kN/m.\"}', NULL, NULL, NULL, 2, 1, 0, NULL, NULL, '2026-05-14 18:09:02', '2026-05-14 18:09:02'),
(20, 7, 'portail-battant-fer-forge', 'wrought-iron-swing-gate', '{\"en\": \"Wrought Iron Swing Gate\", \"fr\": \"Portail battant fer forgé\"}', '{\"en\": \"Custom wrought iron swing gate — scrolls, spear tops, high-quality building-grade epoxy finish.\", \"fr\": \"Portail battant en fer forgé sur mesure — volutes, pointes de flèche, finition époxy qualité bâtiment haut de gamme.\"}', '{\"en\": \"<p>The wrought iron gate remains the reference choice for prestige properties and heritage buildings. Each gate is hand-forged by our Bulgarian craftsmen, with scrolls, twisted bars and spear tops to the agreed design. The architectural-grade epoxy finish resists UV and weathering for 15+ years. Delivered with installation hardware; motorisation available.</p>\", \"fr\": \"<p>Le portail en fer forgé reste le choix de référence pour les propriétés de prestige et les bâtiments patrimoniaux. Chaque portail est forgé à la main par nos artisans bulgares, avec volutes, barreaux torsadés et pointes de flèche selon le dessin convenu. La finition époxy qualité architecturale résiste aux UV et aux intempéries pendant 15+ années. Livraison avec ferrures de pose et motorisation possible.</p>\"}', '{\"en\": \"<ul><li>Hand-forged wrought iron</li><li>Custom patterns: scrolls, twists, spear tops</li><li>UV anti-rust epoxy + forge black finish</li><li>Galvanised hinges and posts included</li><li>Motorisation available</li></ul>\", \"fr\": \"<ul><li>Fer forgé travaillé à la main</li><li>Motifs sur mesure : volutes, torsades, flèches</li><li>Finition époxy antiouille UV + noir forge</li><li>Pentures et gonds galvanisés inclus</li><li>Motorisation disponible</li></ul>\"}', '{\"en\": \"Round and flat wrought iron, 80 µm architectural-grade epoxy.\", \"fr\": \"Fer forgé rond et plat, époxy qualité architecturale 80 µm.\"}', '{\"en\": \"Width 2×0.90 m to 2×2.00 m. Height 1.20–2.50 m. Indicative weight 80–200 kg.\", \"fr\": \"Largeur 2×0,90 m à 2×2,00 m. Hauteur 1,20–2,50 m. Poids indicatif 80–200 kg.\"}', NULL, NULL, NULL, 3, 1, 0, NULL, NULL, '2026-05-14 18:09:02', '2026-05-14 18:09:02'),
(21, 8, 'terrasse-suspendue-acier-bois', 'suspended-steel-timber-deck', '{\"en\": \"Suspended Steel and Timber Deck\", \"fr\": \"Terrasse suspendue acier et bois\"}', '{\"en\": \"Suspended deck on galvanised steel structure — timber or composite decking, integrated railing, 350 kg/m² load.\", \"fr\": \"Terrasse suspendue sur structure acier galvanisé — lames bois ou composite, garde-corps intégré, charge 350 kg/m².\"}', '{\"en\": \"<p>The suspended steel-timber deck combines the structural performance of steel with the warmth of timber. The primary frame is hot-dip galvanised HEA/IPE sections, anchored to the façade with chemical fixings. Secondary galvanised joists support hardwood (cumaru, ipé) or maintenance-free composite deck boards. A stainless cable railing is supplied as a kit.</p>\", \"fr\": \"<p>La terrasse suspendue acier-bois allie la robustesse de l\'acier à l\'esthétique chaleureuse du bois. La structure porteuse est en profilés HEA/IPE galvanisés à chaud, fixée sur la façade par des pattes d\'ancrage chimique. Les solives secondaires en acier galvanisé reçoivent les lames en bois exotique (cumaru, ipé) ou en composite sans entretien. Le garde-corps inox câbles est livré en kit.</p>\"}', '{\"en\": \"<ul><li>Hot-dip galvanised HEA/IPE structure</li><li>Chemical anchor or post foundation fixing</li><li>Hardwood or composite deck boards</li><li>Stainless cable railing included</li><li>Live load 350 kg/m²</li></ul>\", \"fr\": \"<ul><li>Structure HEA/IPE galvanisé à chaud</li><li>Ancrage chimique façade ou poteaux fondation</li><li>Lames bois exotique ou composite</li><li>Garde-corps câbles inox inclus</li><li>Charge utile 350 kg/m²</li></ul>\"}', '{\"en\": \"Galvanised S235 steel. FSC cumaru or Trex/Fiberon composite boards.\", \"fr\": \"Acier S235 galvanisé. Lames cumaru FSC ou composite Trex/Fiberon.\"}', '{\"en\": \"Area up to 60 m². Max cantilever 3 m. Drainage slope 1–2 %.\", \"fr\": \"Surface jusqu\'à 60 m². Porte-à-faux max 3 m. Inclinaison drainage 1–2 %.\"}', NULL, NULL, NULL, 1, 1, 1, NULL, NULL, '2026-05-14 18:09:02', '2026-05-14 18:09:02'),
(22, 8, 'balcon-rapporte-sur-consoles', 'cantilevered-balcony-on-brackets', '{\"en\": \"Cantilevered Balcony on Steel Brackets\", \"fr\": \"Balcon rapporté sur consoles acier\"}', '{\"en\": \"Add-on balcony on welded steel brackets — in-situ concrete or steel floor, glass or stainless railing.\", \"fr\": \"Balcon rapporté sur consoles acier soudées — béton coulé ou plancher acier, garde-corps verre ou inox.\"}', '{\"en\": \"<p>The add-on balcony on steel brackets is the ideal solution for adding outdoor living space to an existing façade without demolition. HEB or UPN brackets are chemically anchored to the load-bearing wall and structurally calculated. The floor plate can be chequerplate, open-grid grating or a concrete slab. The laminated glass or stainless cable railing meets NF P 01-012.</p>\", \"fr\": \"<p>Le balcon rapporté sur consoles acier est la solution idéale pour ajouter un espace extérieur sur une façade existante sans démolition. Les consoles HEB ou UPN sont ancrées chimiquement dans le mur porteur et dimensionnées au calcul. Le plancher peut être en tôle larmée, caillebotis ou dalle béton. Le garde-corps verre feuilleté ou inox câbles est conforme NF P 01-012.</p>\"}', '{\"en\": \"<ul><li>Structurally calculated HEB or UPN brackets</li><li>Chemical anchor into load-bearing wall</li><li>Chequerplate, open-grid or concrete floor</li><li>Glass or cable railing</li><li>Structural calculation note supplied</li></ul>\", \"fr\": \"<ul><li>Consoles HEB ou UPN calculées</li><li>Ancrage chimique mur porteur</li><li>Plancher tôle, caillebotis ou béton</li><li>Garde-corps verre ou câbles</li><li>Note de calcul structure fournie</li></ul>\"}', '{\"en\": \"Galvanised S355 steel. Hilti or Fischer chemical anchors.\", \"fr\": \"Acier S355 galvanisé. Ancrage chimique Hilti ou Fischer.\"}', '{\"en\": \"Cantilever 1–2.5 m. Area 2–20 m². Load 350 kg/m².\", \"fr\": \"Porte-à-faux 1–2,5 m. Surface 2–20 m². Charge 350 kg/m².\"}', NULL, NULL, NULL, 2, 1, 0, NULL, NULL, '2026-05-14 18:09:02', '2026-05-14 18:09:02'),
(23, 8, 'passerelle-inter-batiments', 'inter-building-walkway', '{\"en\": \"Inter-Building Walkway Bridge\", \"fr\": \"Passerelle inter-bâtiments\"}', '{\"en\": \"Steel walkway bridge between two buildings — HEA/IPE structure, open-grid floor, code-compliant railing.\", \"fr\": \"Passerelle acier entre deux bâtiments — structure HEA/IPE, plancher caillebotis, garde-corps réglementaire.\"}', '{\"en\": \"<p>The inter-building walkway connects two buildings or two levels of an industrial site without routing via ground level. The self-supporting steel structure is calculated for 350 to 500 kg/m² live load. The galvanised open-grid floor deck allows rainwater drainage. Labour-code-compliant railings ensure user safety throughout.</p>\", \"fr\": \"<p>La passerelle inter-bâtiments permet de relier deux bâtiments ou deux niveaux d\'un site industriel sans emprunter le sol. La structure autoportante en acier est calculée pour une charge d\'exploitation de 350 à 500 kg/m². Le plancher caillebotis galvanisé assure l\'écoulement des eaux pluviales. Les garde-corps conformes au code du travail assurent la sécurité des utilisateurs.</p>\"}', '{\"en\": \"<ul><li>Self-supporting HEA/IPE structure</li><li>Live load 350–500 kg/m²</li><li>Galvanised open-grid deck</li><li>Labour-code-compliant railing</li><li>Expansion joints for spans > 12 m</li></ul>\", \"fr\": \"<ul><li>Structure HEA/IPE autoportante</li><li>Charge utile 350–500 kg/m²</li><li>Plancher caillebotis galvanisé</li><li>Garde-corps code du travail</li><li>Joints de dilatation si portée > 12 m</li></ul>\"}', '{\"en\": \"Galvanised S235/S355 steel. 30×100 galvanised open-grid grating.\", \"fr\": \"Acier S235/S355 galvanisé. Caillebotis 30×100 galvanisé.\"}', '{\"en\": \"Span 3–15 m. Clear width 1.00–1.50 m. Manufactured to European standards.\", \"fr\": \"Portée 3–15 m. Largeur utile 1,00–1,50 m. Fabrication aux normes européennes.\"}', NULL, NULL, NULL, 3, 1, 0, NULL, NULL, '2026-05-14 18:09:02', '2026-05-15 07:40:30'),
(24, 9, 'rack-stockage-industriel', 'industrial-storage-rack', '{\"en\": \"Industrial Storage Rack\", \"fr\": \"Rack de stockage industriel\"}', '{\"en\": \"Steel pallet rack — up to 3,000 kg per level, RACKING (EN 15512) certified, weld-free assembly.\", \"fr\": \"Rayonnage à palettes acier — charge jusqu\'à 3 000 kg/niveau, certifié RACKING (EN 15512), assemblage sans soudure.\"}', '{\"en\": \"<p>Our industrial storage racks are designed for logistics warehouses and production workshops. S320GD high-strength steel uprights support per-level loads of 1,000 to 3,000 kg. Bolted weld-free assembly simplifies installation and system reconfiguration. Certified to EN 15512 and FEM 10.2.02. Delivered painted RAL 5015 blue or RAL 2004 orange to warehouse standard.</p>\", \"fr\": \"<p>Nos racks de stockage industriel sont conçus pour les entrepôts logistiques et les ateliers de production. Les montants profilés en acier haute résistance S320GD permettent des charges par niveau de 1 000 à 3 000 kg. L\'assemblage bolté sans soudure facilite l\'installation et l\'évolution du système. Certifié selon EN 15512 et FEM 10.2.02. Livré peint RAL 5015 bleu ou RAL 2004 orange selon standard entrepôt.</p>\"}', '{\"en\": \"<ul><li>S320GD steel uprights</li><li>Per-level load 1,000–3,000 kg</li><li>Bolted weld-free assembly</li><li>EN 15512 / FEM 10.2.02 certified</li><li>Anti-crash barrier option</li></ul>\", \"fr\": \"<ul><li>Montants acier S320GD</li><li>Charge par niveau 1 000–3 000 kg</li><li>Assemblage bolté sans soudure</li><li>Certifié EN 15512 / FEM 10.2.02</li><li>Plinthe anti-choc option</li></ul>\"}', '{\"en\": \"Powder-coated S320GD steel. LNP or LPS beams.\", \"fr\": \"Acier S320GD thermolaqué. Lisses LNP ou LPS.\"}', '{\"en\": \"Height up to 12 m. Depth 0.80–1.10 m. Bay width 2.70–3.60 m. Aisle 2.70–3.60 m.\", \"fr\": \"Hauteur jusqu\'à 12 m. Profondeur 0,80–1,10 m. Travée 2,70–3,60 m. Allée 2,70–3,60 m.\"}', NULL, NULL, NULL, 1, 1, 0, NULL, NULL, '2026-05-14 18:09:02', '2026-05-14 18:09:02'),
(25, 9, 'bac-retention-acier-ce', 'steel-spill-containment-bund', '{\"en\": \"CE-Marked Steel Spill Containment Bund\", \"fr\": \"Bac de rétention acier CE\"}', '{\"en\": \"CE-marked welded steel spill containment bund — 100 to 10,000 L capacity, galvanised grid, ICPE compliant.\", \"fr\": \"Bac de rétention acier soudé marquage CE — capacité 100 à 10 000 L, grille caillebotis galvanisé, conforme ICPE.\"}', '{\"en\": \"<p>Our steel containment bunds are fabricated from welded steel plate with a reinforced flat base. They meet ICPE regulatory requirements for the storage of hazardous liquids (hydrocarbons, solvents, chemicals). Retention capacity equals 100% of the largest container or 50% of total stored volume. CE marked to NF EN 1825. Galvanised open-grid grating supplied.</p>\", \"fr\": \"<p>Nos bacs de rétention acier sont fabriqués en tôle acier soudée avec fond plat renforcé. Ils répondent aux exigences réglementaires ICPE pour le stockage de liquides dangereux (hydrocarbures, solvants, produits chimiques). La capacité de rétention est égale à 100 % du plus grand contenant ou 50 % du volume total stocké. Marquage CE selon NF EN 1825. Grille de caillebotis galvanisé fournie.</p>\"}', '{\"en\": \"<ul><li>Welded steel plate flat base</li><li>CE marked NF EN 1825</li><li>Capacity 100–10,000 L</li><li>Galvanised open-grid grating</li><li>ICPE compliant / ATEX option</li></ul>\", \"fr\": \"<ul><li>Tôle acier soudée fond plat</li><li>Marquage CE NF EN 1825</li><li>Capacité 100–10 000 L</li><li>Grille caillebotis galvanisé</li><li>Conforme ICPE / ATEX option</li></ul>\"}', '{\"en\": \"5 mm S235 steel plate + two-component epoxy hydrocarbon-resistant coating.\", \"fr\": \"Tôle acier S235 5 mm + revêtement époxy bicomposant résistant aux hydrocarbures.\"}', '{\"en\": \"Custom dimensions. 5 mm wall thickness. Dual-layer epoxy coating. 24 h leak test certificate supplied.\", \"fr\": \"Dimensions sur mesure. Épaisseur paroi 5 mm. Revêtement époxy bicouche. Test étanchéité 24 h fourni.\"}', NULL, NULL, NULL, 2, 1, 0, NULL, NULL, '2026-05-14 18:09:02', '2026-05-14 18:09:02'),
(26, 9, 'shelter-technique-acier', 'technical-steel-shelter', '{\"en\": \"Technical Steel Shelter\", \"fr\": \"Shelter technique acier\"}', '{\"en\": \"Modular galvanised steel technical shelter — housing for generators, transformers, LV switchgear and plant rooms.\", \"fr\": \"Abri technique modulaire acier galvanisé — accueil groupes électrogènes, transformateurs, TGBT, locaux techniques.\"}', '{\"en\": \"<p>The technical steel shelter is a prefabricated modular building designed to house and protect sensitive technical equipment. The hot-dip galvanised steel frame is clad in steel or PIR sandwich panels to meet thermal requirements. Openings (doors, ventilation louvres, cable entries) are positioned to plan. Turnkey delivery to site in a single piece.</p>\", \"fr\": \"<p>Le shelter technique acier est un bâtiment modulaire préfabriqué destiné à protéger et abriter des équipements techniques sensibles. La structure en acier galvanisé à chaud reçoit une enveloppe de bardage acier ou sandwich PIR selon les exigences thermiques. Les ouvertures (portes, ventilations, passes-câbles) sont positionnées sur plan. Livraison clé en main sur chantier en une seule pièce.</p>\"}', '{\"en\": \"<ul><li>Hot-dip galvanised steel structure</li><li>Steel or PIR sandwich panel cladding</li><li>Double-security door with specialist lock</li><li>Natural or forced ventilation</li><li>Wiring and lighting option</li></ul>\", \"fr\": \"<ul><li>Structure acier galvanisé à chaud</li><li>Bardage acier ou sandwich PIR</li><li>Porte double sécurité avec serrure spécialisée</li><li>Ventilation naturelle ou forcée</li><li>Câblage et éclairage option</li></ul>\"}', '{\"en\": \"S235 Z350 steel structure. Pre-painted steel cladding or 40 mm PIR sandwich panel.\", \"fr\": \"Structure acier S235 Z350. Bardage acier prélaqué ou sandwich PIR 40 mm.\"}', '{\"en\": \"Standard modules 3×3 m, 3×6 m, 6×6 m. Clear internal height 2.50 m. Custom sizes available.\", \"fr\": \"Modules standard 3×3 m, 3×6 m, 6×6 m. Hauteur utile 2,50 m. Sur mesure possible.\"}', NULL, NULL, NULL, 3, 1, 0, NULL, NULL, '2026-05-14 18:09:02', '2026-05-14 18:09:02'),
(27, 6, 'verriere-toit-terrasse-verre', 'glass-rooftop-skylight-structure', '{\"en\": \"Glass Rooftop Skylight Structure\", \"fr\": \"Verrière de toit / toiture vitrée\"}', '{\"en\": \"Metal-framed glazed roof structure for flat roofs or extensions — maximum overhead light with guaranteed weatherproofing.\", \"fr\": \"Structure métallique vitrée pour toiture-terrasse ou extension — lumière zénithale maximale, étanchéité garantie.\"}', '{\"en\": \"<p>The glass rooftop structure floods an interior with natural overhead light. The powder-coated steel or lacquered aluminium frame is engineered to withstand snow and wind loads to NF EN 1991 standards. VSG 33.2 or 44.4 mm safety laminated glass ensures protection in the event of breakage. EPDM high-performance seals guarantee weatherproofing. Ideal for extensions, atriums, verandas and patio roofs.</p>\", \"fr\": \"<p>La verrière de toit transforme un espace intérieur en apportant la lumière naturelle par le dessus. La structure acier thermolaqué ou aluminium laqué est conçue pour résister aux charges de neige et de vent selon les normes NF EN 1991. Le vitrage feuilleté de sécurité VSG 33.2 ou 44.4 mm garantit la protection en cas de bris. Étanchéité assurée par joints EPDM haute performance. Idéale pour extensions, atriums, vérandas et toitures de patio.</p>\"}', '{\"en\": \"<ul><li>Maximum natural overhead daylight</li><li>VSG safety laminated glass</li><li>EPDM weatherproof seals</li><li>Snow and wind resistance to NF EN 1991</li><li>RAL powder coat or lacquered aluminium finish</li></ul>\", \"fr\": \"<ul><li>Lumière zénithale naturelle maximale</li><li>Vitrage feuilleté de sécurité VSG</li><li>Étanchéité joints EPDM</li><li>Résistance neige et vent NF EN 1991</li><li>Finition thermolaquage RAL ou aluminium laqué</li></ul>\"}', '{\"en\": \"Powder-coated steel or aluminium profiles. VSG 33.2–44.4 mm laminated glass.\", \"fr\": \"Profilés acier ou aluminium thermolaqué. Vitrage feuilleté VSG 33.2–44.4 mm.\"}', '{\"en\": \"Max area 40 m². Min pitch 3°. Snow load up to 100 kg/m². Acoustic rating RW ≥ 35 dB.\", \"fr\": \"Surface max 40 m². Pente min 3°. Charge neige jusqu\'à 100 kg/m². Classement acoustique RW ≥ 35 dB.\"}', NULL, NULL, NULL, 3, 1, 0, NULL, NULL, '2026-05-14 18:10:04', '2026-05-14 18:10:04');

