(10, '{\"en\": \"Quality control\", \"fr\": \"Contrôle qualité\"}', '{\"en\": \"Inspection, production monitoring, and compliance with European standards.\", \"fr\": \"Inspection, suivi de production et conformité aux normes européennes.\"}', NULL, NULL, NULL, '05', 'controle-qualite', 1, 4, 0, 5, '2026-05-15 08:09:44', '2026-05-15 08:09:44');

